class ServiceInternalState:
    """Tracks internal state of the service for debugging purposes."""

    def __init__(self):
        self._lock = threading.Lock()
        self.start_time = datetime.utcnow().isoformat()
        self.request_count = 0
        self.error_count = 0
        self.last_error = None
        self.last_error_time = None
        self.active_requests = 0
        self.method_stats = {}
        self.recent_errors = []
        self.max_recent_errors = 50
        self.db_connected = False
        self.cache_connected = False
        self.dependencies = {
            "database": {"status": "simulated", "latency_ms": 0},
            "cache": {"status": "simulated", "latency_ms": 0},
            "auth_service": {"status": "simulated", "latency_ms": 0},
        }

    def record_request(self, method_name):
        with self._lock:
            self.request_count += 1
            self.active_requests += 1
            if method_name not in self.method_stats:
                self.method_stats[method_name] = {
                    "total_calls": 0,
                    "errors": 0,
                    "last_call": None,
                }
            self.method_stats[method_name]["total_calls"] += 1
            self.method_stats[method_name]["last_call"] = datetime.utcnow().isoformat()

    def record_request_complete(self, method_name):
        with self._lock:
            self.active_requests = max(0, self.active_requests - 1)

    def record_error(self, method_name, error_info):
        with self._lock:
            self.error_count += 1
            self.last_error = error_info
            self.last_error_time = datetime.utcnow().isoformat()
            if method_name in self.method_stats:
                self.method_stats[method_name]["errors"] += 1
            self.recent_errors.append({
                "time": self.last_error_time,
                "method": method_name,
                "error": error_info,
            })
            if len(self.recent_errors) > self.max_recent_errors:
                self.recent_errors = self.recent_errors[-self.max_recent_errors:]

    def to_dict(self, component=None):
        with self._lock:
            full_state = {
                "start_time": self.start_time,
                "current_time": datetime.utcnow().isoformat(),
                "request_count": self.request_count,
                "error_count": self.error_count,
                "active_requests": self.active_requests,
                "last_error": self.last_error,
                "last_error_time": self.last_error_time,
                "method_stats": self.method_stats,
                "recent_errors": self.recent_errors,
                "dependencies": self.dependencies,
                "db_connected": self.db_connected,
                "cache_connected": self.cache_connected,
            }
            if component and component in full_state:
                return {component: full_state[component]}
            return full_state


def build_error_details(exception, method_name, internal_state, request_data=None, additional_context=None):
    """Build comprehensive error details for debugging."""
    exc_type, exc_value, exc_tb = sys.exc_info()

    error_details = {
        "error_type": type(exception).__name__,
        "error_message": str(exception),
        "method": method_name,
        "timestamp": datetime.utcnow().isoformat(),
        "stack_trace": traceback.format_exception(exc_type, exc_value, exc_tb),
        "stack_frames": [],
        "request_data": request_data,
        "service_state_snapshot": {
            "request_count": internal_state.request_count,
            "error_count": internal_state.error_count,
            "active_requests": internal_state.active_requests,
            "dependencies": internal_state.dependencies,
            "db_connected": internal_state.db_connected,
            "cache_connected": internal_state.cache_connected,
        },
        "python_version": sys.version,
        "pid": os.getpid(),
        "thread_id": threading.current_thread().ident,
        "thread_name": threading.current_thread().name,
    }

    # Extract detailed frame information
    if exc_tb:
        tb = exc_tb
        while tb is not None:
            frame = tb.tb_frame
            frame_info = {
                "filename": frame.f_code.co_filename,
                "function": frame.f_code.co_name,
                "line_number": tb.tb_lineno,
                "local_variables": {},
            }
            # Capture local variables (sanitized)
            for key, value in frame.f_locals.items():
                try:
                    if key.startswith("_"):
                        continue
                    val_repr = repr(value)
                    if len(val_repr) > 500:
                        val_repr = val_repr[:500] + "...[truncated]"
                    frame_info["local_variables"][key] = val_repr
                except Exception:
                    frame_info["local_variables"][key] = "<unrepresentable>"
            error_details["stack_frames"].append(frame_info)
            tb = tb.tb_next

    if additional_context:
        error_details["additional_context"] = additional_context

    return error_details


def grpc_error_handler(method_name, internal_state):
    """Decorator for gRPC service methods with comprehensive error handling."""
    def decorator(func):
        def wrapper(self, request, context):
            internal_state.record_request(method_name)
            request_data = {}
            try:
                # Serialize request for debugging
                for field in request.DESCRIPTOR.fields:
                    try:
                        request_data[field.name] = getattr(request, field.name)
                    except Exception:
                        request_data[field.name] = "<unable to read>"
            except Exception:
                request_data = {"raw": str(request)}

            try:
                result = func(self, request, context)
                internal_state.record_request_complete(method_name)
                return result
            except grpc.RpcError:
                # Re-raise gRPC errors that were already handled
                internal_state.record_request_complete(method_name)
                raise
            except ValueError as e:
                error_details = build_error_details(
                    e, method_name, internal_state, request_data,
                    additional_context={"category": "validation_error"}
                )
                error_json = json.dumps(error_details, indent=2, default=str)
                internal_state.record_error(method_name, {
                    "type": "ValueError",
                    "message": str(e),
                })
                internal_state.record_request_complete(method_name)

                context.set_code(grpc.StatusCode.INVALID_ARGUMENT)
                context.set_details(error_json)
                return _get_default_response(method_name)

            except KeyError as e:
                error_details = build_error_details(
                    e, method_name, internal_state, request_data,
                    additional_context={"category": "resource_not_found"}
                )
                error_json = json.dumps(error_details, indent=2, default=str)
                internal_state.record_error(method_name, {
                    "type": "KeyError",
                    "message": str(e),
                })
                internal_state.record_request_complete(method_name)

                context.set_code(grpc.StatusCode.NOT_FOUND)
                context.set_details(error_json)
                return _get_default_response(method_name)

            except PermissionError as e:
                error_details = build_error_details(
                    e, method_name, internal_state, request_data,
                    additional_context={"category": "authorization_error"}
                )
                error_json = json.dumps(error_details, indent=2, default=str)
                internal_state.record_error(method_name, {
                    "type": "PermissionError",
                    "message": str(e),
                })
                internal_state.record_request_complete(method_name)

                context.set_code(grpc.StatusCode.PERMISSION_DENIED)
                context.set_details(error_json)
                return _get_default_response(method_name)

            except TimeoutError as e:
                error_details = build_error_details(
                    e, method_name, internal_state, request_data,
                    additional_context={"category": "timeout_error"}
                )
                error_json = json.dumps(error_details, indent=2, default=str)
                internal_state.record_error(method_name, {
                    "type": "TimeoutError",
                    "message": str(e),
                })
                internal_state.record_request_complete(method_name)

                context.set_code(grpc.StatusCode.DEADLINE_EXCEEDED)
                context.set_details(error_json)
                return _get_default_response(method_name)

            except ConnectionError as e:
                error_details = build_error_details(
                    e, method_name, internal_state, request_data,
                    additional_context={"category": "dependency_failure"}
                )
                error_json = json.dumps(error_details, indent=2, default=str)
                internal_state.record_error(method_name, {
                    "type": "ConnectionError",
                    "message": str(e),
                })
                internal_state.record_request_complete(method_name)

                context.set_code(grpc.StatusCode.UNAVAILABLE)
                context.set_details(error_json)
                return _get_default_response(method_name)

            except Exception as e:
                error_details = build_error_details(
                    e, method_name, internal_state, request_data,
                    additional_context={"category": "unhandled_internal_error"}
                )
                error_json = json.dumps(error_details, indent=2, default=str)
                internal_state.record_error(method_name, {
                    "type": type(e).__name__,
                    "message": str(e),
                })
                internal_state.record_request_complete(method_name)

                context.set_code(grpc.StatusCode.INTERNAL)
                context.set_details(error_json)
                return _get_default_response(method_name)

        return wrapper
    return decorator


def _get_default_response(method_name):
    """Return default empty response based on method name."""
    response_map = {
        "GetUser": debug_service_pb2.UserResponse,
        "ProcessOrder": debug_service_pb2.OrderResponse,
        "HealthCheck": debug_service_pb2.HealthResponse,
        "GetServiceState": debug_service_pb2.StateResponse,
    }
    response_class = response_map.get(method_name)
    if response_class:
        return response_class()
    return None


