class DebugServiceServicer(debug_service_pb2_grpc.DebugServiceServicer):
    """gRPC service implementation with comprehensive error handling."""

    def __init__(self):
        self.state = service_state
        self.state.db_connected = True
        self.state.cache_connected = True

    @grpc_error_handler("GetUser", service_state)
    def GetUser(self, request, context):
        """Get user by ID with detailed error handling."""
        user_id = request.user_id

        # Validation
        if not user_id:
            raise ValueError("user_id is required and cannot be empty")

        if not user_id.startswith("user_"):
            raise ValueError(
                f"Invalid user_id format: '{user_id}'. Expected format: 'user_<number>'"
            )

        # Simulate database check
        if not self.state.db_connected:
            raise ConnectionError(
                "Database connection lost. Last known state: "
                f"{self.state.dependencies['database']}"
            )

        # Lookup user
        if user_id not in USERS_DB:
            raise KeyError(
                f"User '{user_id}' not found in database. "
                f"Available users: {list(USERS_DB.keys())}"
            )

        user = USERS_DB[user_id]
        return debug_service_pb2.UserResponse(
            user_id=user_id,
            name=user["name"],
            email=user["email"],
        )

    @grpc_error_handler("ProcessOrder", service_state)
    def ProcessOrder(self, request, context):
        """Process an order with detailed error handling."""
        order_id = request.order_id
        user_id = request.user_id
        amount = request.amount

        # Validation
        if not order_id:
            raise ValueError("order_id is required")
        if not user_id:
            raise ValueError("user_id is required")
        if amount <= 0:
            raise ValueError(f"Invalid amount: {amount}. Amount must be positive.")
        if amount > 10000:
            raise ValueError(
                f"Amount {amount} exceeds maximum allowed (10000). "
                "Requires elevated permissions."
            )

        # Check user exists
        if user_id not in USERS_DB:
            raise KeyError(
                f"Cannot process order for non-existent user '{user_id}'"
            )

        # Simulate permission check
        if user_id == "user_3":
            raise PermissionError(
                f"User '{user_id}' is suspended and cannot place orders. "
                "Contact admin for account reactivation."
            )

        # Simulate timeout for large orders
        if amount > 5000:
            raise TimeoutError(
                f"Order processing timed out for amount {amount}. "
                "The payment gateway did not respond within 30s. "
                f"Gateway status: {self.state.dependencies.get('auth_service', 'unknown')}"
            )

        # Simulate an unexpected error for specific order IDs
        if order_id == "order_crash":
            # This will trigger an unhandled exception
            result = 1 / 0  # noqa: F841

        # Process order
        ORDERS_DB[order_id] = {
            "user_id": user_id,
            "amount": amount,
            "status": "completed",
            "timestamp": datetime.utcnow().isoformat(),
        }

        return debug_service_pb2.OrderResponse(
            order_id=order_id,
            status="completed",
            message=f"Order {order_id} processed successfully for ${amount:.2f}",
        )

    @grpc_error_handler("HealthCheck", service_state)
    def HealthCheck(self, request, context):
        """Health check endpoint."""
        status = "healthy"
        details = {}

        if request.include_details:
            details = {
                "uptime_since": self.state.start_time,
                "total_requests": self.state.request_count,
                "total_errors": self.state.error_count,
                "error_rate": (
                    f"{(self.state.error_count / max(1, self.state.request_count)) * 100:.2f}%"
                ),
                "active_requests": self.state.active_requests,
                "dependencies": self.state.dependencies,
                "db_connected": self.state.db_connected,
                "cache_connected": self.state.cache_connected,
            }

            if self.state.error_count > self.state.request_count * 0.5:
                status = "degraded"
            if not self.state.db_connected:
                status = "unhealthy"

        return debug_service_pb2.HealthResponse(
            status=status,
            details=json.dumps(details, indent=2) if details else "",
        )

    @grpc_error_handler("GetServiceState", service_state)
    def GetServiceState(self, request, context):
        """Get detailed internal service state for debugging."""
        component = request.component if request.component else None
        state_dict = self.state.to_dict(component)
        return debug_service_pb2.StateResponse(
            state_json=json.dumps(state_dict, indent=2, default=str)
        )


class ErrorInterceptor(grpc.ServerInterceptor):
    """Server interceptor that catches any errors not caught by method handlers."""

    def intercept_service(self, continuation, handler_call_details):
        try:
            return continuation(handler_call_details)
        except Exception as e:
            print(f"[INTERCEPTOR] Unhandled error in service routing: {e}")
            print(traceback.format_exc())
            raise


def serve(port=50051):
    """Start the gRPC server."""
    server = grpc.server(
        futures.ThreadPoolExecutor(max_workers=10),
        interceptors=[ErrorInterceptor()],
        options=[
            ("grpc.max_send_message_length", 50 * 1024 * 1024),
            ("grpc.max_receive_message_length", 50 * 1024 * 1024),
        ],
    )
    debug_service_pb2_grpc.add_DebugServiceServicer_to_server(
        DebugServiceServicer(), server
    )
    server.add_insecure_port(f"[::]:{port}")
    server.start()
    print(f"[SERVER] gRPC Debug Service started on port {port}")
    print(f"[SERVER] PID: {os.getpid()}")
    print(f"[SERVER] Start time: {service_state.start_time}")
    return server


